// Number\(null\) = 0 which IS finite - so these functions treat null as 0, not as missing
// This is a gotcha with JS null coercion. Let me verify the edge cases:
console.log\('Number\(null\)', Number\(null\)\); // 0
console.log\('Number\(undefined\)', Number\(undefined\)\); // NaN
console.log\('Number\(\\"abc\\"\)', Number\('abc'\)\); // NaN

// Check clampTravelWindowHours behavior
const { clampTravelWindowHours } = require\('./src/utils/time'\);
// Math.max\(1, Math.min\(24, Math.round\(Number\(null\)\)\)\) = Math.max\(1, Math.min\(24, 0\)\) = 1
console.log\('null:', clampTravelWindowHours\(null\)\); // 1 \(clamped from 0, not fallback!\)
console.log\('undefined:', clampTravelWindowHours\(undefined\)\); // 12 \(fallback\)
console.log\('null,8:', clampTravelWindowHours\(null, 8\)\); // 1 \(null -> 0 -> clamp to 1\)
")

